assert_CommitCompleteness.condition:
txn_state = "committed" implies
        and TargetUUID in c_records
        and c_ins[TargetUUID]  = {"new_in"}
        and c_outs[TargetUUID] = {"new_out"}
        and c_refs[TargetUUID] = {}

assert_RollbackPreservation.condition:
txn_state = "rolled_back" implies
        and TargetUUID in c_records
        and c_ins[TargetUUID]  = {"old_in"}
        and c_outs[TargetUUID] = {"old_out"}
        and c_refs[TargetUUID] = {OtherUUID}
